INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-014e6a52-moex-00011', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-13504c0c', 'sub-aboriginal-014e6a52-01', NULL, 'single_choice', '「醫藥之父希波克拉底（西元前460年－前370年）曾譽接骨木為天然醫藥箱，認為 它是自然界最偉大的治癒植物之一。美洲原住民將其用來調理各種肌膚問題；歐洲 人將它視為生活萬靈丹，大人小孩感冒或換季不適時會在溫涼的接骨木茶裡加入蜂 蜜飲用，舒緩不適感，也是最好的眼睛保養香草之一。還可用來熬煮成果醬、糖漿 和製作甜點。」 根據上文，下列選項何者正確？', '["接骨木被視為天然醫藥箱，因能延年益壽抗老化", "接骨木可應用在醫藥生技、身體保健與甜點食用", "野生的接骨木混合蜂蜜，能有效治療感冒與流感", "最早發現接骨木功效並加以應用的是美洲原住民"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00012', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-13504c0c', 'sub-aboriginal-014e6a52-01', NULL, 'single_choice', '「撰寫講稿，難的是在於如何精準傳達要藉由致詞場合所釋放的訊息，不只是遣詞用 字必須精準，邏輯鋪陳必須正確，同時還要顧及總統的口語發音，以及總統身分的 高度。除此之外，最要掌握的是文氣，因著場合的不同，總統的致詞或要氣勢磅礴， 或要溫暖動人，除了讓在場的聽眾感受到之外，更必須讓透過書面媒體閱讀的廣大 受眾也能體會得到文字中所包涵的力量。而這也是我常常必須動手修改諸多長官與 學者專家所撰擬的文稿，最主要的原因。」 下列選項，最符合本文意旨的是：', '["總統的講稿，需要特別加強氣勢磅礴的力量", "講稿必須考量場合、對象及口語或書面應用", "文稿的修改，是在檢視是否符合應用文體例", "口語講稿和書面文稿，用詞應該保有一致性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "2d4a2c95a108", "answer_pdf_sha1": "f6341680c20d", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "0104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00013', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-75b9659c', 'sub-aboriginal-014e6a52-02', NULL, 'essay', '請依地籍測量實施規則說明建物平面圖測繪邊界之規定為何？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "030aceeca1c1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "1706", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地法概要(包括地籍測量法規)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00014', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-75b9659c', 'sub-aboriginal-014e6a52-02', NULL, 'essay', '土地所有權人應於地籍調查時到場指界，其到場未能完成指界者，地籍
