  ('aboriginal-014e6a52-moex-00016', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-75b9659c', 'sub-aboriginal-014e6a52-02', NULL, 'essay', '私法人購置住宅採許可制之立法目的為何？並請依平均地權條例說明
其限制規定之內容。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "030aceeca1c1", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "1706", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "土地法概要(包括地籍測量法規)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00017', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '重要憲政機關之職位任期必須有所限制，以便人民有機會於一定時間內，重新決定對這些機關之授權。 此為何種憲法原則之內涵？', '["多黨競爭原則", "民主正當性原則", "權力分立原則", "法治國原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00018', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '依憲法及相關司法院大法官解釋，有關軍事與國防，下列敘述何者正確？', '["總統統率全國陸海空軍，全國陸海空軍須效忠總統，保護人民", "國防與軍事事項，由中央立法，地方執行之", "軍事審判機關所行使者，亦屬國家刑罰權之一種，具有司法權之性質", "現役與退役軍人，均不得兼任文官"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00019', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '依司法院釋字第445號解釋意旨，集會自由與言論、講學、著作及出版自由，同屬下列何者之範疇？', '["表演自由", "表現自由", "人身自由", "行為自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL),
  ('aboriginal-014e6a52-moex-00020', 'aboriginal-014e6a52', 'aboriginal-014e6a52-moex-112-6ed013db', 'sub-aboriginal-014e6a52-03', NULL, 'single_choice', '有關結社自由之限制，依司法院大法官解釋，下列敘述何者錯誤？', '["結社自由保障人民團體成立時之命名權及嗣後之更名權", "內政部以行政命令規定「人民團體經主管機關限期整理者，其理監事之職權應即停止」，違反法律 保留原則", "基於國家安全理由，主張共產主義或分裂國土之結社，不受憲法上結社自由之保障", "人民團體法規定職業團體理事長應「由理事就常務理事中選舉之，不設常務理事者，就理事中互選 之」，違反比例原則"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:43+00:00", "source_pdf_sha1": "28a4987213d2", "answer_pdf_sha1": "e2b696b5ba2c", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "614", "s": "0219", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學知識與英文(包括中華民國憲法、原住民族行政及法規、英文)", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "測量製圖"}'::jsonb, NULL)
